-- descriptions and helps
ZO_CreateStringId("MSAL_HELP_TITLE","|c999999AutoLoot+ is a looting manager based on |ceeeeeeCustom rules|c999999. Define what belongs in your bag and let the addon handle the rest with built-in |ceeeeeeDisposers|c999999. Leave behind, mark as junk, deconstruct, destroy — it's all under your control|r")
ZO_CreateStringId("MSAL_HELP_GEAR","|c999999For |ceeeeeeCollected Set Items|c999999 filtered out by the Set Items Filter, the addon will use the subsequent filters in <<1>> to further determine whether to loot it|r")
ZO_CreateStringId("MSAL_HELP_MATERIAL","|c999999Materials will be auto-looted when you have |ceeeeee" .. GetString(SI_CROWN_STORE_MENU_ESO_PLUS_LABEL) .. "|c999999, regardless of filter settings, unless they are stolen|r")
ZO_CreateStringId("MSAL_HELP_MISC","|c999999For some high-value tradeable items, addon supports price comparison via third-party addons (|ceeeeeeTTC, MM, ATT and TSC|c999999 supported). \nFunctions related will be auto added to this menu when you enable them|r")
ZO_CreateStringId("MSAL_HELP_MISC_3RD_ENABLED","|c999999For some high-value tradeable items, addon supports price comparison via third-party addons (|ceeeeeeTTC, MM, ATT and TSC|c999999 supported). \nWhen a third-party source is selected, non-tradable or lack price data items of such type will be looted directly|r")
ZO_CreateStringId("MSAL_HELP_LIST","|c999999The %s and %s provide a flexible way to customize rules, and they are prioritized over all other filters. \nBlacklist is for items you never want the addon to auto-loot under any circumstances (e.g., set gear you want to sell); Whitelist is for items you always want the addon to pick up. \n\nTo add an item, paste its link into the Add Item box and press Enter. To remove an item, use the Remove Item drop-down menu|r")
ZO_CreateStringId("MSAL_HELP_UNBOX","|c999999Auto-unboxes containers when obtained, with |ceeeeee<<1>>|c999999 applied to filtered-out items.\nUse the buttons below to manually unbox any container. Keybindings (PC) and LibRadialMenu (console) supported.|r")
ZO_CreateStringId("MSAL_HELP_UNWANTED","|c999999Disposer performs auto action you set for filtered-out unwanted items|r")
ZO_CreateStringId("MSAL_HELP_UNWANTED_CONSOLE","|c999999Disposer performs auto action you set for filtered-out unwanted items. \n|ceeeeee<<1>>|c999999 feature is available here, with a matching |ceeeeeeAuto-Sell|c999999|r")
