ZO_CreateStringId("MSAL_DISPOSE_LOG_THRESHOLD","Disposed Log Quality Threshold")
ZO_CreateStringId("MSAL_DISPOSE_LOG_THRESHOLD_TOOLTIP","When any disposer set to <<1>>, the chatbox log will also print the slotId, so if you find that the addon has disposed of an item unexpectedly, you can use |cdb8e0b" .. "/lal um slotId" .. "|r command to <<2>> it")
