ZO_CreateStringId("MSAL_UNBOX_CONTAINER_TOOLTIP","Open containers when they are obtained.\n\nIf the container acquired is a daily crafting reward and you are using |cdb8e0bLazy Writ Crafter|r or |cdb8e0bSimpleDailyCraft|r, unboxing will be temporarily disabled to avoid conflicts with their AutoLoot")
ZO_CreateStringId("MSAL_STOLEN_ITEMS_RULE","Stolen Items Rule")
ZO_CreateStringId("MSAL_STOLEN_ITEMS_RULE_TOOLTIP","When set to |ccc922f<<1>>|r, the addon skips stolen items in the loot window\n\nWhen set to |ccc922f<<2>>|r, the addon additionally prevents you from stealing items in the environment while |ccc922fnot hidden|r\n\nWhen set to |ccc922f<<3>>|r, the addon follows your settings to loot stolen items while you are |ccc922fhidden|r")
