ZO_CreateStringId("MSAL_DECON_THRESHOLD","Extra Decon Threshold")
ZO_CreateStringId("MSAL_DECON_THRESHOLD_TOOLTIP","Only available when |ccc922f<<2>>|r is set to |ccc922f<<1>>|r.\n\nAmong gear discarded to the disposer, items with quality at or above the threshold will be registered for deconstruction, while those below will be marked as junk. When set to no threshold, all gear discarded to the disposer will be both <<1>>.\n\nItems that have their own <<3>> option are not affected by this setting")
